-- Seeds the admin-editable Dink config as a bot_config row, so admins can edit
-- RuneLite Dink plugin settings from /admin/config and have the dink-proxy Worker
-- serve them live (it reads this row, falling back to its bundled template).
--
-- Uses dollar-quoting ($json$ … $json$) so the JSON needs no escaping, and an
-- idempotent INSERT … WHERE NOT EXISTS (no unique-constraint dependency) so it is
-- safe to re-run and never clobbers admin edits. {{TOKEN}} is substituted per user
-- by the Worker — keep it intact. Apply by hand in the Supabase SQL editor.

insert into bot_config (config_name, config_group, config_value, description)
select
    'dink_config',
    'features',
    $json${"killCountInterval":50,"combatTaskEnabled":false,"gambleRareNotifMessage":"%USERNAME% has received rare loot at gamble count %COUNT%: \n\n%LOOT%","speedrunEnabled":false,"questEnabled":false,"deathNotifMessage":"%USERNAME% Has shit a brick","collectionNotifMessage":"%USERNAME% has added %ITEM% to their collection","levelNotifyVirtual":true,"questNotifMessage":"%USERNAME% has completed a quest: %QUEST%","killCountEnabled":false,"petWebhook":"https://dink-proxy.voltionosrs.workers.dev/hook/{{TOKEN}}/achievements","slayerNotifMessage":"%USERNAME% has completed a slayer task: %TASK%, getting %POINTS% points and making that %TASKCOUNT% tasks completed","levelInterval":1,"notifyTrades":false,"speedrunMessage":"%USERNAME% has just finished a speedrun of %QUEST% with a time of %TIME% (their PB is %BEST%)","sendDiscordUser":true,"clueSendImage":true,"chatNotifyMessage":"%USERNAME% received a chat message:\n\n```\n%MESSAGE%\n```","slayerEnabled":false,"deathEnabled":true,"combatTaskUnlockMessage":"%USERNAME% has unlocked the rewards for the %COMPLETED% tier, by completing the combat task: %TASK%","deathMinValue":0,"deniedAccountTypes":[],"lootIncludeClueScrolls":true,"pkIncludeLocation":true,"lootIcons":true,"collectionWebhook":"https://dink-proxy.voltionosrs.workers.dev/hook/{{TOKEN}}/collection","lootEnabled":true,"petNotifMessage":"%USERNAME% %GAME_MESSAGE%","nameFilterMode":"DENY","lootRarityThreshold":0,"maxRetries":3,"speedrunPBOnly":true,"embedFooterText":"Powered by Dink","includeLocation":true,"groupStorageNotifyMessage":"%USERNAME% has deposited:\n%DEPOSITED%\n\n%USERNAME% has withdrawn:\n%WITHDRAWN%","deathEmbedProtected":false,"useSlayerWidgetKc":true,"diarySendImage":true,"questSendImage":true,"killCountSendImage":true,"sendGroupIronClanName":true,"speedrunSendImage":true,"lootRarityValueIntersection":false,"levelEnabled":false,"petEnabled":true,"chatMessageTypes":["GAME","COMMAND"],"tradeMinValue":0,"externalSendImage":"REQUESTED","slayerPointThreshold":0,"lootItemAllowlist":"Leviathan's lure\nSiren's staff\nExecutioner's axe head\nEye of the duke\nMagus vestige\nUltor vestige\nBellator vestige\nVenator vestige","petSendImage":true,"groupStorageMinValue":0,"embedFooterIcon":"https://github.com/pajlads/DinkPlugin/raw/master/icon.png","killCountInitial":true,"combatTaskSendImage":true,"lootSendImage":true,"pkSendImage":true,"deathNotifPvpEnabled":true,"gambleInterval":100,"combatTaskMessage":"%USERNAME% has completed %TIER% combat task: %TASK%","notifyExternal":false,"collectionLogEnabled":true,"grandExchangeSendImage":true,"speedrunPBMessage":"%USERNAME% has just beat their personal best in a speedrun of %QUEST% with a time of %TIME%","deathSendImage":true,"lootImageMinValue":3000000,"diaryMinDifficulty":"EASY","clueMinTier":"BEGINNER","pkNotifyMessage":"%USERNAME% has PK'd %TARGET%","killCountPenanceQueen":true,"baseRetryDelay":2000,"deathWebhook":"https://dink-proxy.voltionosrs.workers.dev/hook/{{TOKEN}}/deaths","clueImageMinValue":0,"lootIncludeGambles":false,"deathIgnoreSafe":true,"levelMinValue":1,"includeClientFrame":false,"levelIntervalOverride":0,"grandExchangeProgressSpacingMinutes":-1,"gambleSendImage":true,"pkEnabled":false,"imageWriteTimeout":30,"gambleNotifMessage":"%USERNAME% has reached %COUNT% high gambles","clueNotifMessage":"%USERNAME% has completed a %CLUE% clue, they have completed %COUNT%.\nThey obtained:\n\n%LOOT%","lootSourceDenylist":"Einar\n","gambleRareLoot":true,"clueEnabled":false,"lootWebhook":"https://dink-proxy.voltionosrs.workers.dev/hook/{{TOKEN}}/achievements","clueMinValue":0,"levelSendImage":true,"embedColor":"#FFF40098","chatPrivacy":"HIDE_SPLIT_PM","deathIgnoredRegions":"123, 456, 789","chatSendImage":true,"groupStorageIncludeClan":true,"levelMinScreenshotValue":1,"pkSkipSafe":true,"levelNotifyCombat":false,"sendClanName":true,"threadNameTemplate":"[%TYPE%] %MESSAGE%","playerLookupService":"OSRS_HISCORE","discordWebhook":"https://dink-proxy.voltionosrs.workers.dev/hook/{{TOKEN}}/achievements","tradeNotifyMessage":"%USERNAME% traded with %COUNTERPARTY%","lootIncludePlayer":false,"combatTaskMinTier":"EASY","grandExchangeIncludeCancelled":false,"seasonalPolicy":"REJECT","deathSafeExceptions":["INFERNO","COX","GAUNTLET","TOB","TOA"],"groupStorageSendImage":true,"levelNotifMessage":"%USERNAME% has levelled %SKILL%","killCountBestTimeMessage":"%USERNAME% has defeated %BOSS% with a new personal best time of %TIME% and a completion count of %COUNT%","collectionSendImage":true,"screenshotScale":100,"notifyChat":false,"lootNotifMessage":"%USERNAME% has looted: \n\n%LOOT%\nFrom: %SOURCE%","chatPatterns":"You've unlocked an emote: *\nYou've completed the * event*\nYou have accepted * into *.\nYou will be logged out in approximately 30 minutes.*\nYou will be logged out in approximately 10 minutes.*\n::TriggerDink\n","diaryEnabled":false,"deathNotifPvpMessage":"%USERNAME% has just been PKed by %PKER% for %VALUELOST% gp...","groupStorageEnabled":false,"diaryMessage":"%USERNAME% has completed the %DIFFICULTY% %AREA% Achievement Diary, for a total of %TOTAL% diaries completed","minLootValue":1,"pkMinValue":0,"notifyGrandExchange":false,"grandExchangeNotifyMessage":"%USERNAME% %TYPE% %ITEM% on the GE","killCountPB":true,"discordRichEmbeds":true,"slayerSendImage":true,"tradeSendImage":true,"grandExchangeMinValue":100000,"xpInterval":5,"clueShowItems":false,"killCountMessage":"%USERNAME% has defeated %BOSS% with a completion count of %COUNT%","groupStorageIncludePrice":true,"pkSkipFriendly":false,"lootRedirectPlayerKill":false,"gambleEnabled":false}$json$::jsonb,
    $desc$RuneLite Dink plugin config served live by dink-proxy. Edit to change clan-wide Dink settings (thresholds, notifier toggles, messages) without a redeploy. {{TOKEN}} is substituted per user — do not remove it.$desc$
where not exists (select 1 from bot_config where config_name = $key$dink_config$key$);
